import{_ as s,c as a,a as e,o as t}from"./app-DiLCLBG1.js";const p="/learning-2023-flutter/assets/bdd-BbLKWbDa.png",i={};function l(c,n){return t(),a("div",null,n[0]||(n[0]=[e(`<h1 id="persistence" tabindex="-1"><a class="header-anchor" href="#persistence"><span>Persistence</span></a></h1><h2 id="use-sharedpreferences" tabindex="-1"><a class="header-anchor" href="#use-sharedpreferences"><span>Use sharedPreferences</span></a></h2><h4 id="definition" tabindex="-1"><a class="header-anchor" href="#definition"><span>Definition</span></a></h4><p>Shared Preferences provide a simple way to store key-value pairs persistently.</p><p>Shared preference is an API that will store un an XML file simple data types like int, double, bool, String and StringList or json encoded objects.</p><h4 id="dependency-declaration" tabindex="-1"><a class="header-anchor" href="#dependency-declaration"><span>Dependency declaration</span></a></h4><div class="language-yaml line-numbers-mode" data-highlighter="prismjs" data-ext="yml" data-title="yml"><pre><code><span class="line">flutter pub add shared_preferences</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h4 id="save-data" tabindex="-1"><a class="header-anchor" href="#save-data"><span>Save data</span></a></h4><div class="language-dart line-numbers-mode" data-highlighter="prismjs" data-ext="dart" data-title="dart"><pre><code><span class="line"><span class="token comment">// Load and obtain the shared preferences for this app.</span></span>
<span class="line"><span class="token keyword">final</span> prefs <span class="token operator">=</span> <span class="token keyword">await</span> <span class="token class-name">SharedPreferences</span><span class="token punctuation">.</span><span class="token function">getInstance</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// Save the counter value to persistent storage under the &#39;counter&#39; key.</span></span>
<span class="line"><span class="token keyword">await</span> prefs<span class="token punctuation">.</span><span class="token function">setInt</span><span class="token punctuation">(</span><span class="token string-literal"><span class="token string">&#39;counter&#39;</span></span><span class="token punctuation">,</span> counter<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="read-data" tabindex="-1"><a class="header-anchor" href="#read-data"><span>Read data</span></a></h4><div class="language-dart line-numbers-mode" data-highlighter="prismjs" data-ext="dart" data-title="dart"><pre><code><span class="line"><span class="token keyword">final</span> prefs <span class="token operator">=</span> <span class="token keyword">await</span> <span class="token class-name">SharedPreferences</span><span class="token punctuation">.</span><span class="token function">getInstance</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// Try reading the counter value from persistent storage.</span></span>
<span class="line"><span class="token comment">// If not present, null is returned, so default to 0.</span></span>
<span class="line"><span class="token keyword">final</span> counter <span class="token operator">=</span> prefs<span class="token punctuation">.</span><span class="token function">getInt</span><span class="token punctuation">(</span><span class="token string-literal"><span class="token string">&#39;counter&#39;</span></span><span class="token punctuation">)</span> <span class="token operator">?</span><span class="token operator">?</span> <span class="token number">0</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="🧪-exercise" tabindex="-1"><a class="header-anchor" href="#🧪-exercise"><span>🧪 Exercise</span></a></h2><div class="hint-container warning"><p class="hint-container-title">Exercise 1 - Use shared preferences to store quiz data and timestamp of last successful API fetch.</p><p>Use SharedPreferences to</p><ul><li>Store the json quiz data fetched from the API on a String key &quot;quiz_data&quot;.</li><li>Store an integer value containing the timestamp of the last successful API fetch.</li><li>On app launch, check if there is quiz data stored in SharedPreferences than is less than 5 minutes old.</li><li>if yes, load the quiz data from SharedPreferences</li><li>if no, fetch the quiz data from the API, store it in SharedPreferences along with the new timestamp.</li></ul><div class="hint-container tip"><p class="hint-container-title">Complete Solution</p><details class="hint-container details"><summary>Expand</summary><ul><li>Check it on Zapp : <a href="https://zapp.run/edit/flutter-zhhc06v0hhd0" target="_blank" rel="noopener noreferrer">https://zapp.run/edit/flutter-zhhc06v0hhd0</a></li><li>or download the project code <a href="https://github.com/gbrah/learning-2023-flutter/raw/refs/heads/main/docs/src/assets/sources/step4-sharedprefs.zip" target="_blank" rel="noopener noreferrer">here 💾</a></li></ul></details></div></div><h2 id="use-database" tabindex="-1"><a class="header-anchor" href="#use-database"><span>Use database</span></a></h2><p>SQLite is a powerful and lightweight relational database that&#39;s commonly used for data storage in Flutter apps.</p><div class="hint-container tip"><p class="hint-container-title">Why use SQLite?</p><p>On mobile development, SQLite is a popular choice for local data storage due to its efficiency and ease of use. It is mainly used for offline data storage, caching, and managing structured data.</p></div><p>There is multiple packages to use SQLite in Flutter from low-level to high-level abstractions. The most popular ones are <a href="https://pub.dev/packages/sqflite" target="_blank" rel="noopener noreferrer"><code>sqflite</code></a> and <a href="https://pub.dev/packages/drift/example" target="_blank" rel="noopener noreferrer"><code>drift</code></a>. Sqflite is a low-level package that provides direct access to SQLite databases, while drift is a higher-level package that offers an ORM-like experience with type safety and reactive programming features. Sqflite supports both Android and iOS platforms, while drift supports Android, iOS, and web platforms. The choice between the two depends on your specific needs and preferences for database management in your Flutter app.</p><div class="hint-container warning"><p class="hint-container-title">support</p><p>sqlflite is not supported on web platform.</p></div><h4 id="dependency-declaration-1" tabindex="-1"><a class="header-anchor" href="#dependency-declaration-1"><span>Dependency declaration</span></a></h4><div class="language-yaml line-numbers-mode" data-highlighter="prismjs" data-ext="yml" data-title="yml"><pre><code><span class="line">flutter pub add sqflite</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>or add to the pubspec.yaml file</p><div class="language-yaml line-numbers-mode" data-highlighter="prismjs" data-ext="yml" data-title="yml"><pre><code><span class="line"><span class="token key atrule">dependencies</span><span class="token punctuation">:</span></span>
<span class="line">  <span class="token key atrule">sqflite</span><span class="token punctuation">:</span> ^2.0.0+4</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="creating-sqlite-databases" tabindex="-1"><a class="header-anchor" href="#creating-sqlite-databases"><span>Creating SQLite databases.</span></a></h3><div class="language-dart line-numbers-mode" data-highlighter="prismjs" data-ext="dart" data-title="dart"><pre><code><span class="line"><span class="token keyword">import</span> <span class="token string-literal"><span class="token string">&#39;package:sqflite/sqflite.dart&#39;</span></span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// Open the database and store the reference.</span></span>
<span class="line"><span class="token keyword">final</span> database <span class="token operator">=</span> <span class="token function">openDatabase</span><span class="token punctuation">(</span></span>
<span class="line">   <span class="token comment">// Set the path to the database.</span></span>
<span class="line">   <span class="token function">join</span><span class="token punctuation">(</span><span class="token keyword">await</span> <span class="token function">getDatabasesPath</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">,</span> <span class="token string-literal"><span class="token string">&#39;quiz_database.db&#39;</span></span><span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">   <span class="token comment">// When the database is first created, create a table to store quizzes.</span></span>
<span class="line">   onCreate<span class="token punctuation">:</span> <span class="token punctuation">(</span>db<span class="token punctuation">,</span> version<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">       <span class="token keyword">return</span> db<span class="token punctuation">.</span><span class="token function">execute</span><span class="token punctuation">(</span></span>
<span class="line">             <span class="token string-literal"><span class="token string">&#39;CREATE TABLE quizzes(id INTEGER PRIMARY KEY, question TEXT, answer TEXT)&#39;</span></span><span class="token punctuation">,</span></span>
<span class="line">          <span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">   <span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line">   <span class="token comment">// Set the version. This executes the onCreate function and provides a</span></span>
<span class="line">   <span class="token comment">// path to perform database upgrades and downgrades.</span></span>
<span class="line">   version<span class="token punctuation">:</span> <span class="token number">1</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="performing-crud" tabindex="-1"><a class="header-anchor" href="#performing-crud"><span>Performing CRUD</span></a></h3><p>CRUD operations (Create, Read, Update, Delete) are fundamental for managing data in a database. Here are examples of how to perform CRUD operations using the sqflite package in Flutter.</p><h5 id="insert-data" tabindex="-1"><a class="header-anchor" href="#insert-data"><span>Insert data</span></a></h5><div class="language-dart line-numbers-mode" data-highlighter="prismjs" data-ext="dart" data-title="dart"><pre><code><span class="line"><span class="token class-name">Future</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token keyword">void</span><span class="token punctuation">&gt;</span></span> <span class="token function">insertQuiz</span><span class="token punctuation">(</span><span class="token class-name">Quiz</span> quiz<span class="token punctuation">)</span> <span class="token keyword">async</span> <span class="token punctuation">{</span></span>
<span class="line">   <span class="token comment">// Get a reference to the database.</span></span>
<span class="line">   <span class="token keyword">final</span> db <span class="token operator">=</span> <span class="token keyword">await</span> database<span class="token punctuation">;</span>    </span>
<span class="line">   <span class="token comment">// Insert the Quiz into the correct table. Also specify the</span></span>
<span class="line">   <span class="token comment">// \`conflictAlgorithm\`. In this case, if the same quiz is inserted</span></span>
<span class="line">   <span class="token comment">// multiple times, it replaces the previous data.</span></span>
<span class="line">   <span class="token keyword">await</span> db<span class="token punctuation">.</span><span class="token function">insert</span><span class="token punctuation">(</span></span>
<span class="line">         <span class="token string-literal"><span class="token string">&#39;quizzes&#39;</span></span><span class="token punctuation">,</span></span>
<span class="line">         quiz<span class="token punctuation">.</span><span class="token function">toMap</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">         conflictAlgorithm<span class="token punctuation">:</span> <span class="token class-name">ConflictAlgorithm</span><span class="token punctuation">.</span>replace<span class="token punctuation">,</span></span>
<span class="line">   <span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h5 id="read-data-1" tabindex="-1"><a class="header-anchor" href="#read-data-1"><span>Read data</span></a></h5><div class="language-dart line-numbers-mode" data-highlighter="prismjs" data-ext="dart" data-title="dart"><pre><code><span class="line"><span class="token class-name">Future</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token class-name">List</span><span class="token punctuation">&lt;</span><span class="token class-name">Quiz</span><span class="token punctuation">&gt;</span><span class="token punctuation">&gt;</span></span> <span class="token function">quizzes</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token keyword">async</span> <span class="token punctuation">{</span></span>
<span class="line">   <span class="token comment">// Get a reference to the database.</span></span>
<span class="line">   <span class="token keyword">final</span> db <span class="token operator">=</span> <span class="token keyword">await</span> database<span class="token punctuation">;</span></span>
<span class="line">   <span class="token comment">// Query the table for all The Quizzes.</span></span>
<span class="line">   <span class="token keyword">final</span> <span class="token class-name">List</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token class-name">Map</span><span class="token punctuation">&lt;</span><span class="token class-name">String</span><span class="token punctuation">,</span> <span class="token keyword">dynamic</span><span class="token punctuation">&gt;</span><span class="token punctuation">&gt;</span></span> maps <span class="token operator">=</span> <span class="token keyword">await</span> db<span class="token punctuation">.</span><span class="token function">query</span><span class="token punctuation">(</span><span class="token string-literal"><span class="token string">&#39;quizzes&#39;</span></span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">   <span class="token comment">// Convert the List&lt;Map&lt;String, dynamic&gt; into a List&lt;Quiz&gt;.</span></span>
<span class="line">   <span class="token keyword">return</span> <span class="token class-name">List</span><span class="token punctuation">.</span><span class="token function">generate</span><span class="token punctuation">(</span>maps<span class="token punctuation">.</span>length<span class="token punctuation">,</span> <span class="token punctuation">(</span>i<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">         <span class="token keyword">return</span> <span class="token class-name">Quiz</span><span class="token punctuation">(</span></span>
<span class="line">               id<span class="token punctuation">:</span> maps<span class="token punctuation">[</span>i<span class="token punctuation">]</span><span class="token punctuation">[</span><span class="token string-literal"><span class="token string">&#39;id&#39;</span></span><span class="token punctuation">]</span><span class="token punctuation">,</span></span>
<span class="line">               question<span class="token punctuation">:</span> maps<span class="token punctuation">[</span>i<span class="token punctuation">]</span><span class="token punctuation">[</span><span class="token string-literal"><span class="token string">&#39;question&#39;</span></span><span class="token punctuation">]</span><span class="token punctuation">,</span></span>
<span class="line">               answer<span class="token punctuation">:</span> maps<span class="token punctuation">[</span>i<span class="token punctuation">]</span><span class="token punctuation">[</span><span class="token string-literal"><span class="token string">&#39;answer&#39;</span></span><span class="token punctuation">]</span><span class="token punctuation">,</span></span>
<span class="line">         <span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">   <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h5 id="update-data" tabindex="-1"><a class="header-anchor" href="#update-data"><span>Update data</span></a></h5><div class="language-dart line-numbers-mode" data-highlighter="prismjs" data-ext="dart" data-title="dart"><pre><code><span class="line"><span class="token class-name">Future</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token keyword">void</span><span class="token punctuation">&gt;</span></span> <span class="token function">updateQuiz</span><span class="token punctuation">(</span><span class="token class-name">Quiz</span> quiz<span class="token punctuation">)</span> <span class="token keyword">async</span> <span class="token punctuation">{</span></span>
<span class="line">   <span class="token comment">// Get a reference to the database.</span></span>
<span class="line">   <span class="token keyword">final</span> db <span class="token operator">=</span> <span class="token keyword">await</span> database<span class="token punctuation">;</span></span>
<span class="line">   <span class="token comment">// Update the given Quiz.</span></span>
<span class="line">   <span class="token keyword">await</span> db<span class="token punctuation">.</span><span class="token function">update</span><span class="token punctuation">(</span></span>
<span class="line">         <span class="token string-literal"><span class="token string">&#39;quizzes&#39;</span></span><span class="token punctuation">,</span></span>
<span class="line">         quiz<span class="token punctuation">.</span><span class="token function">toMap</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">         <span class="token comment">// Ensure that the Quiz has a matching id.</span></span>
<span class="line">         where<span class="token punctuation">:</span> <span class="token string-literal"><span class="token string">&#39;id = ?&#39;</span></span><span class="token punctuation">,</span></span>
<span class="line">         <span class="token comment">// Pass the Quiz&#39;s id as a whereArg to prevent SQL injection.</span></span>
<span class="line">         whereArgs<span class="token punctuation">:</span> <span class="token punctuation">[</span>quiz<span class="token punctuation">.</span>id<span class="token punctuation">]</span><span class="token punctuation">,</span></span>
<span class="line">   <span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h5 id="delete-data" tabindex="-1"><a class="header-anchor" href="#delete-data"><span>Delete data</span></a></h5><div class="language-dart line-numbers-mode" data-highlighter="prismjs" data-ext="dart" data-title="dart"><pre><code><span class="line"><span class="token class-name">Future</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token keyword">void</span><span class="token punctuation">&gt;</span></span> <span class="token function">deleteQuiz</span><span class="token punctuation">(</span>int id<span class="token punctuation">)</span> <span class="token keyword">async</span> <span class="token punctuation">{</span></span>
<span class="line">   <span class="token comment">// Get a reference to the database.</span></span>
<span class="line">   <span class="token keyword">final</span> db <span class="token operator">=</span> <span class="token keyword">await</span> database<span class="token punctuation">;</span></span>
<span class="line">   <span class="token comment">// Remove the Quiz from the database.</span></span>
<span class="line">   <span class="token keyword">await</span> db<span class="token punctuation">.</span><span class="token function">delete</span><span class="token punctuation">(</span></span>
<span class="line">         <span class="token string-literal"><span class="token string">&#39;quizzes&#39;</span></span><span class="token punctuation">,</span></span>
<span class="line">         <span class="token comment">// Use a \`where\` clause to delete a specific quiz.</span></span>
<span class="line">         where<span class="token punctuation">:</span> <span class="token string-literal"><span class="token string">&#39;id = ?&#39;</span></span><span class="token punctuation">,</span></span>
<span class="line">         <span class="token comment">// Pass the Quiz&#39;s id as a whereArg to prevent SQL injection.</span></span>
<span class="line">         whereArgs<span class="token punctuation">:</span> <span class="token punctuation">[</span>id<span class="token punctuation">]</span><span class="token punctuation">,</span></span>
<span class="line">   <span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="prepare-the-data-model" tabindex="-1"><a class="header-anchor" href="#prepare-the-data-model"><span>Prepare the data model</span></a></h4><p>Because sqflite queries return a <code>List&lt;Map&lt;String, dynamic&gt;&gt;</code>, it&#39;s common to create a data model class that represents the structure of the data and provides methods for converting between the database format and the Dart object format. This makes it easier to work with the data in your application. Here is an example of a complex data type with sub-mapping.</p><div class="language-dart line-numbers-mode" data-highlighter="prismjs" data-ext="dart" data-title="dart"><pre><code><span class="line"><span class="token keyword">class</span> <span class="token class-name">Question</span> <span class="token punctuation">{</span></span>
<span class="line">  <span class="token keyword">final</span> <span class="token class-name">String</span> text<span class="token punctuation">;</span></span>
<span class="line">  <span class="token keyword">final</span> <span class="token class-name">List</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token class-name">Answer</span><span class="token punctuation">&gt;</span></span> answers<span class="token punctuation">;</span></span>
<span class="line">   <span class="token class-name">Question</span><span class="token punctuation">(</span><span class="token punctuation">{</span>required <span class="token keyword">this</span><span class="token punctuation">.</span>text<span class="token punctuation">,</span> required <span class="token keyword">this</span><span class="token punctuation">.</span>answers<span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">   <span class="token class-name">Map</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token class-name">String</span><span class="token punctuation">,</span> <span class="token keyword">dynamic</span><span class="token punctuation">&gt;</span></span> <span class="token function">toMap</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">       <span class="token keyword">return</span> <span class="token punctuation">{</span></span>
<span class="line">             <span class="token string-literal"><span class="token string">&#39;text&#39;</span></span><span class="token punctuation">:</span> text<span class="token punctuation">,</span></span>
<span class="line">             <span class="token comment">//  answers need to be converted to map</span></span>
<span class="line">               <span class="token string-literal"><span class="token string">&#39;answers&#39;</span></span><span class="token punctuation">:</span> answers<span class="token punctuation">.</span><span class="token function">map</span><span class="token punctuation">(</span><span class="token punctuation">(</span>answer<span class="token punctuation">)</span> <span class="token operator">=</span><span class="token operator">&gt;</span> answer<span class="token punctuation">.</span><span class="token function">toMap</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">toList</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">       <span class="token punctuation">}</span><span class="token punctuation">;</span></span>
<span class="line">   <span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="transactions" tabindex="-1"><a class="header-anchor" href="#transactions"><span>Transactions</span></a></h3><p>You can also perform transactions to execute multiple operations atomically, ensuring data integrity and consistency. Transactions allow you to group multiple database operations together, and if any operation fails, the entire transaction can be rolled back to maintain a consistent state.</p><p>here is an example of using transactions to insert a quiz and its associated answers atomically:</p><div class="language-dart line-numbers-mode" data-highlighter="prismjs" data-ext="dart" data-title="dart"><pre><code><span class="line"><span class="token class-name">Future</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token keyword">void</span><span class="token punctuation">&gt;</span></span> <span class="token function">insertQuizWithAnswers</span><span class="token punctuation">(</span><span class="token class-name">Quiz</span> quiz<span class="token punctuation">)</span> <span class="token keyword">async</span> <span class="token punctuation">{</span></span>
<span class="line">   <span class="token keyword">final</span> db <span class="token operator">=</span> <span class="token keyword">await</span> database<span class="token punctuation">;</span></span>
<span class="line">   <span class="token keyword">await</span> db<span class="token punctuation">.</span><span class="token function">transaction</span><span class="token punctuation">(</span><span class="token punctuation">(</span>txn<span class="token punctuation">)</span> <span class="token keyword">async</span> <span class="token punctuation">{</span></span>
<span class="line">         <span class="token comment">// Insert the quiz and get its generated id</span></span>
<span class="line">         int quizId <span class="token operator">=</span> <span class="token keyword">await</span> txn<span class="token punctuation">.</span><span class="token function">insert</span><span class="token punctuation">(</span><span class="token string-literal"><span class="token string">&#39;quizzes&#39;</span></span><span class="token punctuation">,</span> quiz<span class="token punctuation">.</span><span class="token function">toMap</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">         <span class="token comment">// Insert each answer associated with the quiz</span></span>
<span class="line">         <span class="token keyword">for</span> <span class="token punctuation">(</span><span class="token keyword">var</span> answer <span class="token keyword">in</span> quiz<span class="token punctuation">.</span>answers<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">               <span class="token keyword">await</span> txn<span class="token punctuation">.</span><span class="token function">insert</span><span class="token punctuation">(</span><span class="token string-literal"><span class="token string">&#39;answers&#39;</span></span><span class="token punctuation">,</span> <span class="token punctuation">{</span>  </span>
<span class="line">                     <span class="token string-literal"><span class="token string">&#39;quiz_id&#39;</span></span><span class="token punctuation">:</span> quizId<span class="token punctuation">,</span> <span class="token comment">// Foreign key to associate with the quiz</span></span>
<span class="line">                     <span class="token string-literal"><span class="token string">&#39;text&#39;</span></span><span class="token punctuation">:</span> answer<span class="token punctuation">.</span>text<span class="token punctuation">,</span></span>
<span class="line">                     <span class="token string-literal"><span class="token string">&#39;is_correct&#39;</span></span><span class="token punctuation">:</span> answer<span class="token punctuation">.</span>isCorrect <span class="token operator">?</span> <span class="token number">1</span> <span class="token punctuation">:</span> <span class="token number">0</span><span class="token punctuation">,</span></span>
<span class="line">               <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">         <span class="token punctuation">}</span></span>
<span class="line">   <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="🧪-exercise-1" tabindex="-1"><a class="header-anchor" href="#🧪-exercise-1"><span>🧪 Exercise</span></a></h2><div class="hint-container warning"><p class="hint-container-title">Step 1 - Sqflite dependency declaration</p><p>Declare the dependency for sqflite in your pubspec.yaml file and run flutter pub get to install it.</p></div><div class="hint-container warning"><p class="hint-container-title">Step 2 - Database initialization</p><p>Initialize the database by creating the necessary tables and setting up the schema.</p><p>Implement the following database schema to store quiz questions and answers: <img src="`+p+`" alt="Quiz Database"></p><p>To not overcomplicate the exercise, please find below a sample code snippet for database initialization with the above schema. You can modify it as needed.</p><details class="hint-container details"><summary>Database initialization</summary><div class="language-dart line-numbers-mode" data-highlighter="prismjs" data-ext="dart" data-title="dart"><pre><code><span class="line"><span class="token class-name">Database</span><span class="token operator">?</span> _database<span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line">  <span class="token class-name">Future</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token class-name">Database</span><span class="token punctuation">&gt;</span></span> <span class="token keyword">get</span> database <span class="token keyword">async</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">if</span> <span class="token punctuation">(</span>_database <span class="token operator">!=</span> <span class="token keyword">null</span><span class="token punctuation">)</span> <span class="token keyword">return</span> _database<span class="token operator">!</span><span class="token punctuation">;</span></span>
<span class="line">    _database <span class="token operator">=</span> <span class="token keyword">await</span> <span class="token function">_initDatabase</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">    <span class="token keyword">return</span> _database<span class="token operator">!</span><span class="token punctuation">;</span></span>
<span class="line">  <span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line">  <span class="token class-name">Future</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token class-name">Database</span><span class="token punctuation">&gt;</span></span> <span class="token function">_initDatabase</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token keyword">async</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">final</span> path <span class="token operator">=</span> <span class="token keyword">await</span> <span class="token function">getDatabasesPath</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">    <span class="token keyword">final</span> dbPath <span class="token operator">=</span> <span class="token function">join</span><span class="token punctuation">(</span>path<span class="token punctuation">,</span> <span class="token string-literal"><span class="token string">&#39;quiz.db&#39;</span></span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line">    <span class="token keyword">return</span> <span class="token keyword">await</span> <span class="token function">openDatabase</span><span class="token punctuation">(</span></span>
<span class="line">      dbPath<span class="token punctuation">,</span></span>
<span class="line">      version<span class="token punctuation">:</span> <span class="token number">1</span><span class="token punctuation">,</span></span>
<span class="line">      onCreate<span class="token punctuation">:</span> <span class="token punctuation">(</span>db<span class="token punctuation">,</span> version<span class="token punctuation">)</span> <span class="token keyword">async</span> <span class="token punctuation">{</span></span>
<span class="line">        <span class="token keyword">await</span> db<span class="token punctuation">.</span><span class="token function">execute</span><span class="token punctuation">(</span><span class="token string-literal"><span class="token string">&#39;&#39;&#39;</span>
<span class="line">          CREATE TABLE questions (</span>
<span class="line">            id INTEGER PRIMARY KEY,</span>
<span class="line">            label TEXT NOT NULL,</span>
<span class="line">            correct_answer_id INTEGER NOT NULL</span>
<span class="line">          )</span>
<span class="line">        &#39;&#39;&#39;</span></span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">        <span class="token keyword">await</span> db<span class="token punctuation">.</span><span class="token function">execute</span><span class="token punctuation">(</span><span class="token string-literal"><span class="token string">&#39;&#39;&#39;</span>
<span class="line">          CREATE TABLE answers (</span>
<span class="line">            id INTEGER,</span>
<span class="line">            label TEXT NOT NULL,</span>
<span class="line">            question_id INTEGER NOT NULL,</span>
<span class="line">            PRIMARY KEY (id, question_id),</span>
<span class="line">            FOREIGN KEY (question_id) REFERENCES questions (id) ON DELETE CASCADE</span>
<span class="line">          )</span>
<span class="line">        &#39;&#39;&#39;</span></span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">      <span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">  <span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></details></div><div class="hint-container warning"><p class="hint-container-title">Step 3 - Evolve the data model to support database storage conversion</p><p>Create methods for converting between the database Map format and Dart objects for the quiz questions and answers. This will make it easier to work with the data in your application.</p></div><div class="hint-container warning"><p class="hint-container-title">Step 4 - CRUD functions implementation</p><p>Implement functions to perform Create, Read, Update, and Delete (CRUD) operations on the quiz questions and answers in the database. This will allow you to manage the quiz data effectively.</p></div><div class="hint-container warning"><p class="hint-container-title">Step 5 - Use the database &amp; Implement data caching strategy</p><ol><li>First app launch <strong>with</strong> network: <ul><li>Make an <strong>API request</strong> and store in the database.</li></ul></li><li>First app launch <strong>without</strong> network: <ul><li>Generate a <strong>mock</strong> list of questions.</li></ul></li><li>App launch <strong>without</strong> network: <ul><li>Return data from the <strong>database</strong> even if it&#39;s old data. App launch with network, with the last request <strong>within 5 minutes</strong>:</li><li>Return data from the <strong>database</strong>.</li></ul></li><li>App launch with network, with the last request <strong>over 5 minutes</strong> ago: <ul><li>Make an <strong>API request</strong>, return the data, and store in the database, store also the timestamp of the last successful request.</li></ul></li></ol></div><div class="hint-container tip"><p class="hint-container-title">Complete solution</p><details class="hint-container details"><summary>Expand</summary><ul><li>Check it on Zapp : <a href="https://zapp.run/edit/flutter-z0sk06bg0sl0" target="_blank" rel="noopener noreferrer">https://zapp.run/edit/flutter-z0sk06bg0sl0</a></li><li>or download the project code <a href="https://github.com/gbrah/learning-2023-flutter/raw/refs/heads/main/docs/src/assets/sources/step5-database.zip" target="_blank" rel="noopener noreferrer">here 💾</a></li></ul></details></div><h2 id="file-i-o" tabindex="-1"><a class="header-anchor" href="#file-i-o"><span>File I/O</span></a></h2><p>File I/O allows you to read and write files on the device&#39;s file system. This can be useful for storing larger amounts of data or for working with files that need to be accessed outside of the app.</p><div class="language-dart line-numbers-mode" data-highlighter="prismjs" data-ext="dart" data-title="dart"><pre><code><span class="line"><span class="token keyword">import</span> <span class="token string-literal"><span class="token string">&#39;dart:io&#39;</span></span><span class="token punctuation">;</span></span>
<span class="line"><span class="token keyword">import</span> <span class="token string-literal"><span class="token string">&#39;package:path_provider/path_provider.dart&#39;</span></span><span class="token punctuation">;</span>  </span>
<span class="line"></span>
<span class="line"><span class="token class-name">Future</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token class-name">String</span><span class="token punctuation">&gt;</span></span> <span class="token keyword">get</span> _localPath <span class="token keyword">async</span> <span class="token punctuation">{</span></span>
<span class="line">   <span class="token keyword">final</span> directory <span class="token operator">=</span> <span class="token keyword">await</span> <span class="token function">getApplicationDocumentsDirectory</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">   <span class="token keyword">return</span> directory<span class="token punctuation">.</span>path<span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token class-name">Future</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token class-name">File</span><span class="token punctuation">&gt;</span></span> <span class="token keyword">get</span> _localFile <span class="token keyword">async</span> <span class="token punctuation">{</span></span>
<span class="line">   <span class="token keyword">final</span> path <span class="token operator">=</span> <span class="token keyword">await</span> _localPath<span class="token punctuation">;</span></span>
<span class="line">   <span class="token keyword">return</span> <span class="token class-name">File</span><span class="token punctuation">(</span><span class="token string-literal"><span class="token string">&#39;</span><span class="token interpolation"><span class="token punctuation">$</span><span class="token expression">path</span></span><span class="token string">/quiz_data.txt&#39;</span></span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token class-name">Future</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token class-name">File</span><span class="token punctuation">&gt;</span></span> <span class="token function">writeQuizData</span><span class="token punctuation">(</span><span class="token class-name">String</span> data<span class="token punctuation">)</span> <span class="token keyword">async</span> <span class="token punctuation">{</span></span>
<span class="line">   <span class="token keyword">final</span> file <span class="token operator">=</span> <span class="token keyword">await</span> _localFile<span class="token punctuation">;</span></span>
<span class="line">   <span class="token keyword">return</span> file<span class="token punctuation">.</span><span class="token function">writeAsString</span><span class="token punctuation">(</span>data<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token class-name">Future</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token class-name">String</span><span class="token punctuation">&gt;</span></span> <span class="token function">readQuizData</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token keyword">async</span> <span class="token punctuation">{</span></span>
<span class="line">   <span class="token keyword">try</span> <span class="token punctuation">{</span></span>
<span class="line">         <span class="token keyword">final</span> file <span class="token operator">=</span> <span class="token keyword">await</span> _localFile<span class="token punctuation">;</span></span>
<span class="line">         <span class="token class-name">String</span> contents <span class="token operator">=</span> <span class="token keyword">await</span> file<span class="token punctuation">.</span><span class="token function">readAsString</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">         <span class="token keyword">return</span> contents<span class="token punctuation">;</span></span>
<span class="line">   <span class="token punctuation">}</span> <span class="token keyword">catch</span> <span class="token punctuation">(</span>e<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">         <span class="token keyword">return</span> <span class="token string-literal"><span class="token string">&#39;Error: </span><span class="token interpolation"><span class="token punctuation">$</span><span class="token expression">e</span></span><span class="token string">&#39;</span></span><span class="token punctuation">;</span></span>
<span class="line">   <span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="📖-further-reading" tabindex="-1"><a class="header-anchor" href="#📖-further-reading"><span>📖 Further reading</span></a></h2><ul><li><a href="https://docs.flutter.dev/cookbook/persistence/sqlite" target="_blank" rel="noopener noreferrer">SQLite</a></li><li><a href="https://docs.flutter.dev/cookbook/persistence/key-value" target="_blank" rel="noopener noreferrer">SharedPrefs</a></li></ul>`,53)]))}const r=s(i,[["render",l],["__file","index.html.vue"]]),u=JSON.parse('{"path":"/7.persistance/","title":"Persistence","lang":"en-US","frontmatter":{"description":"Persistence Use sharedPreferences Definition Shared Preferences provide a simple way to store key-value pairs persistently. Shared preference is an API that will store un an XML...","head":[["meta",{"property":"og:url","content":"https://worldline.github.io/gbrah/learning-2023-flutter/learning-2023-flutter/7.persistance/"}],["meta",{"property":"og:title","content":"Persistence"}],["meta",{"property":"og:description","content":"Persistence Use sharedPreferences Definition Shared Preferences provide a simple way to store key-value pairs persistently. Shared preference is an API that will store un an XML..."}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"en-US"}],["meta",{"property":"og:updated_time","content":"2026-03-25T08:31:11.000Z"}],["meta",{"property":"article:modified_time","content":"2026-03-25T08:31:11.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"Persistence\\",\\"image\\":[\\"\\"],\\"dateModified\\":\\"2026-03-25T08:31:11.000Z\\",\\"author\\":[]}"]]},"headers":[{"level":2,"title":"Use sharedPreferences","slug":"use-sharedpreferences","link":"#use-sharedpreferences","children":[]},{"level":2,"title":"🧪 Exercise","slug":"🧪-exercise","link":"#🧪-exercise","children":[]},{"level":2,"title":"Use database","slug":"use-database","link":"#use-database","children":[{"level":3,"title":"Creating SQLite databases.","slug":"creating-sqlite-databases","link":"#creating-sqlite-databases","children":[]},{"level":3,"title":"Performing CRUD","slug":"performing-crud","link":"#performing-crud","children":[]},{"level":3,"title":"Transactions","slug":"transactions","link":"#transactions","children":[]}]},{"level":2,"title":"🧪 Exercise","slug":"🧪-exercise-1","link":"#🧪-exercise-1","children":[]},{"level":2,"title":"File I/O","slug":"file-i-o","link":"#file-i-o","children":[]},{"level":2,"title":"📖 Further reading","slug":"📖-further-reading","link":"#📖-further-reading","children":[]}],"git":{"updatedTime":1774427471000,"contributors":[{"name":"Brah","email":"brah.gharbi@gmail.com","commits":9,"url":"https://github.com/Brah"},{"name":"A187839","email":"ibrahim.gharbi@worldline.com","commits":4,"url":"https://github.com/A187839"}]},"filePathRelative":"7.persistance/README.md","autoDesc":true}');export{r as comp,u as data};
